'use client';

import { useComponentConfig } from '../config-provider/context';
import TreeUI from './TreeUI';
import type { TreeItemData, TreeProps } from './types';

const Tree = <T extends TreeItemData = TreeItemData>({ ref, ...props }: TreeProps<T>) => {
  const config = useComponentConfig('tree');

  const mergedProps = { ...config, ...props };

  return (
    <TreeUI
      ref={ref}
      {...mergedProps}
    />
  );
};

export default Tree;

'use client';

import { useMemo } from 'react';
import { cn } from '@/lib/utils';
import { useTreeRootContext } from './context';
import { flattenChildren, handleAndDispatchCustomEvent, recurseCheckChildren } from './shared';
import { getIndentStyle } from './tree-variants';
import type { TreeItemProps, TreeItemRenderProps, TreeSelectEvent, TreeToggleEvent } from './types';

const TREE_SELECT = 'tree.select';
const TREE_TOGGLE = 'tree.toggle';

const TreeItem = (props: TreeItemProps) => {
  const { value, level, disabled: itemDisabled, disabledSelect, disabledToggle, onSelect, onToggle, children, className, indentSize, style, ...rest } = props;

  const {
    modelValue,
    disabled: rootDisabled,
    selectedKeys,
    expanded,
    expandedItems,
    propagateSelect,
    bubbleSelect,
    onSelect: contextOnSelect,
    onToggle: contextOnToggle
  } = useTreeRootContext('TreeItem');

  const currentItem = useMemo(() => expandedItems.find(item => item.value === value), [expandedItems, value]);

  const disabled = rootDisabled || itemDisabled;

  const hasChildren = Boolean(currentItem?.hasChildren);

  const isExpanded = expanded.includes(value);

  const isSelected = selectedKeys.includes(value);

  const hasSelectedChildren = recurseCheckChildren(selectedKeys, currentItem?.data?.children);

  const isIndeterminate = useMemo(() => {
    if (!currentItem || !hasChildren || !Array.isArray(modelValue)) {
      return undefined;
    }
    const children = flattenChildren(currentItem.data.children);
    if (bubbleSelect) {
      const someSelected = children.some(child => selectedKeys.includes(child.value));
      const allSelected = children.every(child => selectedKeys.includes(child.value));
      return someSelected && !allSelected;
    }
    else if (propagateSelect && isSelected) {
      return !children.every(child => selectedKeys.includes(child.value));
    }
    return undefined;
  }, [currentItem, hasChildren, modelValue, bubbleSelect, propagateSelect, isSelected, selectedKeys]);

  const handleSelect = (event: TreeSelectEvent) => {
    onSelect?.(event);
    if (!event.defaultPrevented) {
      contextOnSelect(value);
    }
  };

  const handleToggle = (event: TreeToggleEvent) => {
    onToggle?.(event);

    if (!event.defaultPrevented) {
      contextOnToggle(value);
    }
  };

  function handleToggleCustomEvent(event?: MouseEvent) {
    if (disabledToggle || !event)
      return;

    const eventDetail = {
      originalEvent: event,
      value,
      isExpanded,
      isSelected
    };
    handleAndDispatchCustomEvent(TREE_TOGGLE, handleToggle, eventDetail);
  }

  function handleSelectCustomEvent(event?: MouseEvent) {
    if (disabledSelect || !event)
      return;

    const eventDetail = {
      originalEvent: event,
      value,
      isExpanded,
      isSelected
    };
    handleAndDispatchCustomEvent(TREE_SELECT, handleSelect, eventDetail);
  }

  const handleClick = (event: React.MouseEvent<HTMLLIElement>) => {
    if (disabled) {
      return;
    }
    event.stopPropagation();

    handleSelectCustomEvent(event.nativeEvent);

    handleToggleCustomEvent(event.nativeEvent);
  };

  const renderProps: TreeItemRenderProps = { isExpanded, isSelected, isIndeterminate, hasChildren };

  const indentStyle = getIndentStyle(level, indentSize);

  return (
    <li
      aria-disabled={disabled || undefined}
      aria-expanded={hasChildren ? isExpanded : undefined}
      aria-level={level}
      aria-selected={isSelected}
      className={cn(className)}
      data-contains-selected={hasSelectedChildren ? '' : undefined}
      data-disabled={disabled ? '' : undefined}
      data-expanded={isExpanded ? '' : undefined}
      data-indent={level}
      data-selected={isSelected ? '' : undefined}
      data-value={value}
      role="treeitem"
      style={{ ...indentStyle, ...style }}
      tabIndex={isSelected ? 0 : -1}
      onClick={handleClick}
      {...rest}
    >
      {typeof children === 'function' ? children(renderProps) : children}
    </li>
  );
};

export default TreeItem;

'use client';

import { useCallback, useMemo, useRef } from 'react';
import { useControllableState } from '@radix-ui/react-use-controllable-state';
import { useComposedRefs } from '@radix-ui/react-compose-refs';
import { cn } from '@/lib/utils';
import { TreeRootProvider } from './context';
import { flattenChildren, flattenItems, findParentPath } from './shared';
import type { FlattenedItem, TreeItemData, TreeRootProps } from './types';
import { useAutoAnimate } from './hooks';

const TreeRoot = <T extends TreeItemData = TreeItemData>(props: TreeRootProps<T>) => {
  const {
    items,
    value: controlledValue,
    defaultValue,
    onValueChange,
    expanded: controlledExpanded,
    defaultExpanded = [],
    onExpandedChange,
    multiple,
    selectionBehavior = 'toggle',
    toggleBehavior = 'multiple',
    disabled,
    propagateSelect,
    ref,
    top,
    bottom,
    bubbleSelect,
    allowParentSelect,
    size,
    className,
    children,
    ...rest
  } = props;

  const [animateRef] = useAutoAnimate();

  const firstValue = useRef<string>('');

  const interRef = useComposedRefs(animateRef, ref);

  const [modelValue, setModelValue] = useControllableState({
    caller: 'tree-root',
    defaultProp: defaultValue ?? (multiple ? [] : ''),
    onChange: onValueChange,
    prop: controlledValue
  });

  const [expanded, setExpanded] = useControllableState({
    caller: 'tree-root-expanded',
    defaultProp: defaultExpanded,
    onChange: onExpandedChange,
    prop: controlledExpanded
  });

  const selectedKeys = useMemo(() => {
    if (multiple && Array.isArray(modelValue)) {
      return modelValue;
    }
    return modelValue ? [modelValue] as string[] : [];
  }, [multiple, modelValue]);

  const expandedItems = flattenItems(items, expanded);

  const onSelect = useCallback((value: string) => {
    if (disabled) {
      return;
    }

    const item = expandedItems.find(i => i.value === value);

    if (item?.hasChildren && !allowParentSelect) {
      return;
    }

    let newValue: string | string[];

    if (multiple && Array.isArray(modelValue)) {
      if (selectionBehavior === 'replace') {
        newValue = [value];
        firstValue.current = value;
      }
      else {
        const index = modelValue.findIndex(v => v === value);
        newValue = index !== -1 ? modelValue.filter(v => v !== value) : [...modelValue, value];
      }
    }
    else if (selectionBehavior === 'replace') {
      newValue = value;
    }
    else if (!Array.isArray(modelValue) && modelValue === value) {
      newValue = '';
    }
    else {
      newValue = value;
    }

    if (bubbleSelect && multiple && Array.isArray(newValue) && item) {
      const bubbleUp = (currentItem: FlattenedItem<TreeItemData>) => {
        if (!currentItem.parent) {
          return;
        }
        const parentItem = expandedItems.find(i => i.value === currentItem.parent?.value);
        if (!parentItem) {
          return;
        }
        const isAllSelected = parentItem.data.children?.every(child => (newValue as string[]).includes(child.value));
        if (isAllSelected) {
          newValue = [...newValue as string[], parentItem.data.value];
        }
        else {
          newValue = (newValue as string[]).filter(v => v !== parentItem.data.value);
        }
        bubbleUp(parentItem);
      };
      bubbleUp(item);
    }

    if (propagateSelect && multiple && Array.isArray(newValue) && item) {
      const children = flattenChildren(item.data.children);
      const isSelected = newValue.includes(value);
      if (isSelected) {
        newValue = newValue.filter(v => !children.some(child => child.value === v));
      }
      else {
        newValue = [...newValue, ...children.map(child => child.value)];
      }
    }

    setModelValue(newValue);
  }, [disabled, expandedItems, allowParentSelect, multiple, modelValue, selectionBehavior, bubbleSelect, propagateSelect, setModelValue]);

  const onToggle = useCallback((value: string) => {
    if (disabled) {
      return;
    }
    const item = expandedItems.find(i => i.value === value);
    if (!item?.data?.children) {
      return;
    }
    if (expanded.includes(value)) {
      setExpanded(expanded.filter(v => v !== value));
      return;
    }
    if (toggleBehavior === 'single') {
      const parentPath = findParentPath(value, items);
      setExpanded(parentPath ? [...parentPath, value] : [value]);
    }
    else {
      setExpanded([...expanded, value]);
    }
  }, [disabled, expandedItems, expanded, toggleBehavior, items, setExpanded]);

  const contextValue = useMemo(() => ({
    modelValue,
    expanded,
    selectedKeys,
    expandedItems,
    items,
    multiple,
    disabled,
    selectionBehavior,
    propagateSelect,
    bubbleSelect,
    allowParentSelect,
    isVirtual: false,
    size,
    onSelect,
    onToggle
  }), [modelValue, selectedKeys, expanded, expandedItems, items, multiple, disabled, selectionBehavior, propagateSelect, bubbleSelect, allowParentSelect, size, onSelect, onToggle]);

  return (
    <TreeRootProvider value={contextValue}>
      <ul
        aria-disabled={disabled || undefined}
        aria-multiselectable={multiple || undefined}
        className={cn(className)}
        data-disabled={disabled ? '' : undefined}
        ref={interRef}
        role="tree"
        {...rest}
      >
        {top}

        {
          // eslint-disable-next-line react-hooks/refs
          children({
            flattenItems: expandedItems,
            modelValue,
            expanded,
            select: onSelect,
            toggle: onToggle
          })
        }

        {bottom}
      </ul>
    </TreeRootProvider>
  );
};

export default TreeRoot;

'use client';

import { Icon } from '../icon';
import TreeItem from './TreeItem';
import TreeRoot from './TreeRoot';
import type { FlattenedItem, TreeItemData, TreeProps } from './types';

const DefaultIndicator = ({ isExpanded }: { isExpanded: boolean }) => {
  return (
    <span
      className="flex shrink-0 items-center justify-center transition-transform duration-200 data-[expanded]:rotate-90"
      data-expanded={isExpanded ? '' : undefined}
    >
      <Icon
        className="transition-transform duration-200"
        icon="lucide:chevron-right"
        style={{ transform: isExpanded ? 'rotate(90deg)' : 'rotate(0deg)' }}
      />
    </span>
  );
};

const TreeUI = <T extends TreeItemData = TreeItemData>(props: TreeProps<T>) => {
  const { items, className, renderItem, classNames, size, onSelect, onToggle, indentSize, disabledToggle, disabledSelect, ref, ...rest } = props;

  const defaultRenderItemContent = (item: FlattenedItem<T>, isExpanded: boolean, hasChildren: boolean, isSelected: boolean) => {
    const indicator = hasChildren
      ? (
        <DefaultIndicator
          isExpanded={isExpanded}
        />
      )
      : <span className="w-4" />;
    const label = 'label' in item.data ? (item.data).label : item.value;
    return (
      <div
        className="hover:bg-muted focus-visible:ring-primary data-[selected]:bg-primary/10 data-[selected]:text-primary flex size-full items-center gap-2 rounded-md py-2 transition-colors duration-150 focus-visible:ring-2 focus-visible:ring-offset-1 focus-visible:outline-none data-[disabled]:hover:bg-transparent"
        data-selected={isSelected ? '' : undefined}
      >
        {indicator}
        <span className="flex-1 truncate">{label}</span>
      </div>
    );
  };

  return (
    <TreeRoot
      className={className || classNames?.root}
      items={items}
      ref={ref}
      size={size}
      {...rest}
    >
      {({ flattenItems, modelValue, expanded, select, toggle }) => flattenItems.map(item => (
        <TreeItem
          className={classNames?.item}
          disabled={item.data.disabled}
          disabledSelect={disabledSelect}
          disabledToggle={disabledToggle}
          indentSize={indentSize}
          key={item._id}
          level={item.level}
          value={item.value}
          onSelect={onSelect}
          onToggle={onToggle}
        >
          {({ isExpanded, isSelected, isIndeterminate, hasChildren }) =>
            renderItem ? renderItem({ item, isExpanded, isSelected, isIndeterminate, hasChildren, flattenItems, modelValue, expanded, select, toggle }) : defaultRenderItemContent(item, isExpanded, hasChildren, isSelected)}
        </TreeItem>
      ))}
    </TreeRoot>
  );
};

export default TreeUI;

'use client';
/* eslint-disable react-hooks/incompatible-library */

import type { CSSProperties, ReactNode, Ref } from 'react';
import { useCallback, useImperativeHandle, useMemo, useRef } from 'react';
import { useVirtualizer, type Virtualizer } from '@tanstack/react-virtual';
import { useControllableState } from '@radix-ui/react-use-controllable-state';
import { cn } from '@/lib/utils';
import { Icon } from '../icon';
import { TreeRootProvider } from './context';
import { flattenChildren, flattenItems, findParentPath } from './shared';
import { treeVariants } from './tree-variants';
import TreeItem from './TreeItem';
import type {
  FlattenedItem,
  TreeItemData,
  TreeItemProps,
  TreeItemRenderProps,
  TreeRootProps,
  TreeRootRenderProps,
  TreeClassNames
} from './types';

export interface TreeVirtualizerProps<T extends TreeItemData = TreeItemData>
  extends Omit<TreeRootProps<T>, 'children' | 'onSelect' | 'onToggle' | 'onScroll'>,
  Pick<TreeItemProps, 'onSelect' | 'onToggle' | 'indentSize' | 'disabledToggle' | 'disabledSelect'> {
  /**
   * Height of the virtual container
   */
  height: number | string;
  /**
   * Width of the virtual container
   */
  width?: number | string;
  /**
   * Estimated item height for virtualization
   */
  itemSize?: number | ((index: number) => number);
  /**
   * Custom class names for component slots
   */
  classNames?: TreeClassNames & {
    virtualContainer?: string;
    virtualContent?: string;
  };
  /**
   * Custom render function for each tree item
   */
  renderItem?: (props: TreeItemRenderProps & { item: FlattenedItem<T> } & TreeRootRenderProps<T>) => ReactNode;
  /**
   * Reference to the virtualizer instance
   */
  virtualizerRef?: Ref<TreeVirtualizerRef<T> | null>;
  /**
   * Callback when scroll offset changes
   */
  onScroll?: (offset: number) => void;
  /**
   * Whether to use dynamic item size measurement
   */
  dynamic?: boolean;
  /**
   * Overscan count for rendering extra items
   */
  overscan?: number;
}

export interface TreeVirtualizerRef<T extends TreeItemData = TreeItemData> {
  containerRef: HTMLDivElement | null;
  virtualizer: Virtualizer<HTMLDivElement, Element>;
  flattenItems: FlattenedItem<T>[];
  scrollToIndex: (index: number, options?: { align?: 'start' | 'center' | 'end' | 'auto' }) => void;
  scrollToValue: (value: string, options?: { align?: 'start' | 'center' | 'end' | 'auto' }) => void;
}

const DefaultIndicator = ({ isExpanded }: { isExpanded: boolean }) => {
  return (
    <span
      className="flex shrink-0 items-center justify-center transition-transform duration-200"
      data-expanded={isExpanded ? '' : undefined}
    >
      <Icon
        className="size-full transition-transform duration-200"
        icon="lucide:chevron-right"
        style={{ transform: isExpanded ? 'rotate(90deg)' : 'rotate(0deg)' }}
      />
    </span>
  );
};

const TreeVirtualizer = <T extends TreeItemData = TreeItemData>(props: TreeVirtualizerProps<T>) => {
  const {
    items,
    value: controlledValue,
    defaultValue,
    onValueChange,
    expanded: controlledExpanded,
    defaultExpanded = [],
    onExpandedChange,
    multiple,
    selectionBehavior = 'toggle',
    toggleBehavior = 'multiple',
    disabled,
    propagateSelect,
    bubbleSelect,
    allowParentSelect,
    size,
    className,
    classNames,
    ref,
    top,
    bottom,
    // Virtual props
    height,
    width,
    itemSize = 36,
    renderItem,
    virtualizerRef,
    onScroll,
    dynamic,
    overscan = 5,
    // TreeItem props
    onSelect,
    onToggle,
    indentSize,
    disabledToggle,
    disabledSelect,
    ..._rest
  } = props;

  const { virtualContainer, virtualContent } = treeVariants();

  const rootRef = useRef<HTMLDivElement>(null);
  const firstValue = useRef<string>('');

  const [modelValue, setModelValue] = useControllableState({
    caller: 'tree-virtualizer',
    defaultProp: defaultValue ?? (multiple ? [] : ''),
    onChange: onValueChange,
    prop: controlledValue
  });

  const [expanded, setExpanded] = useControllableState({
    caller: 'tree-virtualizer-expanded',
    defaultProp: defaultExpanded,
    onChange: onExpandedChange,
    prop: controlledExpanded
  });

  const selectedKeys = useMemo(() => {
    if (multiple && Array.isArray(modelValue)) {
      return modelValue;
    }
    return modelValue ? [modelValue] as string[] : [];
  }, [multiple, modelValue]);

  const expandedItems = useMemo(() => flattenItems(items, expanded), [items, expanded]);

  const handleSelect = useCallback((value: string) => {
    if (disabled) {
      return;
    }

    const item = expandedItems.find(i => i.value === value);

    if (item?.hasChildren && !allowParentSelect) {
      return;
    }

    let newValue: string | string[];

    if (multiple && Array.isArray(modelValue)) {
      if (selectionBehavior === 'replace') {
        newValue = [value];
        firstValue.current = value;
      }
      else {
        const index = modelValue.findIndex(v => v === value);
        newValue = index !== -1 ? modelValue.filter(v => v !== value) : [...modelValue, value];
      }
    }
    else if (selectionBehavior === 'replace') {
      newValue = value;
    }
    else if (!Array.isArray(modelValue) && modelValue === value) {
      newValue = '';
    }
    else {
      newValue = value;
    }

    if (bubbleSelect && multiple && Array.isArray(newValue) && item) {
      const bubbleUp = (currentItem: FlattenedItem<TreeItemData>) => {
        if (!currentItem.parent) {
          return;
        }
        const parentItem = expandedItems.find(i => i.value === currentItem.parent?.value);
        if (!parentItem) {
          return;
        }
        const isAllSelected = parentItem.data.children?.every(child => (newValue as string[]).includes(child.value));
        if (isAllSelected) {
          newValue = [...newValue as string[], parentItem.data.value];
        }
        else {
          newValue = (newValue as string[]).filter(v => v !== parentItem.data.value);
        }
        bubbleUp(parentItem);
      };
      bubbleUp(item);
    }

    if (propagateSelect && multiple && Array.isArray(newValue) && item) {
      const children = flattenChildren(item.data.children);
      const isSelected = newValue.includes(value);
      if (isSelected) {
        newValue = newValue.filter(v => !children.some(child => child.value === v));
      }
      else {
        newValue = [...newValue, ...children.map(child => child.value)];
      }
    }

    setModelValue(newValue);
  }, [disabled, expandedItems, allowParentSelect, multiple, modelValue, selectionBehavior, bubbleSelect, propagateSelect, setModelValue]);

  const handleToggle = useCallback((value: string) => {
    if (disabled) {
      return;
    }
    const item = expandedItems.find(i => i.value === value);
    if (!item?.data?.children) {
      return;
    }
    if (expanded.includes(value)) {
      setExpanded(expanded.filter(v => v !== value));
      return;
    }
    if (toggleBehavior === 'single') {
      const parentPath = findParentPath(value, items);
      setExpanded(parentPath ? [...parentPath, value] : [value]);
    }
    else {
      setExpanded([...expanded, value]);
    }
  }, [disabled, expandedItems, expanded, toggleBehavior, items, setExpanded]);

  function getEstimateSize(index: number) {
    if (typeof itemSize === 'function') {
      return itemSize(index);
    }
    return itemSize;
  }

  const virtualizer = useVirtualizer({
    getScrollElement: () => rootRef.current,
    count: expandedItems.length,
    estimateSize: getEstimateSize,
    overscan,
    onChange: (instance) => {
      onScroll?.(instance.scrollOffset ?? 0);
    }
  });

  const virtualItems = virtualizer.getVirtualItems();
  const totalSize = virtualizer.getTotalSize();

  const scrollToIndex = useCallback((index: number, options?: { align?: 'start' | 'center' | 'end' | 'auto' }) => {
    virtualizer.scrollToIndex(index, options);
  }, [virtualizer]);

  const scrollToValue = useCallback((value: string, options?: { align?: 'start' | 'center' | 'end' | 'auto' }) => {
    const index = expandedItems.findIndex(item => item.value === value);
    if (index !== -1) {
      virtualizer.scrollToIndex(index, options);
    }
  }, [virtualizer, expandedItems]);

  useImperativeHandle(virtualizerRef, () => ({
    containerRef: rootRef.current,
    virtualizer,
    flattenItems: expandedItems,
    scrollToIndex,
    scrollToValue
  }), [virtualizer, expandedItems, scrollToIndex, scrollToValue]);

  const contextValue = useMemo(() => ({
    modelValue,
    expanded,
    selectedKeys,
    expandedItems,
    items,
    multiple,
    disabled,
    selectionBehavior,
    propagateSelect,
    bubbleSelect,
    allowParentSelect,
    isVirtual: true,
    size,
    onSelect: handleSelect,
    onToggle: handleToggle
  }), [modelValue, selectedKeys, expanded, expandedItems, items, multiple, disabled, selectionBehavior, propagateSelect, bubbleSelect, allowParentSelect, size, handleSelect, handleToggle]);

  const containerStyle: CSSProperties = {
    height,
    width: width ?? '100%',
    overflow: 'auto',
    contain: 'strict'
  };

  const contentStyle: CSSProperties = {
    height: totalSize,
    width: '100%',
    position: 'relative'
  };

  const defaultRenderItemContent = (item: FlattenedItem<T>, isExpanded: boolean, hasChildren: boolean) => {
    const indicator = hasChildren
      ? (
        <DefaultIndicator isExpanded={isExpanded} />
      )
      : <span className="w-4" />;
    const label = 'label' in item.data ? (item.data).label : item.value;
    return (
      <>
        {indicator}
        <span className="flex-1 truncate">{label}</span>
      </>
    );
  };

  const renderProps: TreeRootRenderProps<T> = {
    flattenItems: expandedItems,
    modelValue,
    expanded,
    select: handleSelect,
    toggle: handleToggle
  };

  const renderContent = () => {
    if (dynamic) {
      return (
        <div
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            transform: `translateY(${virtualItems[0]?.start ?? 0}px)`
          }}
        >
          {virtualItems.map((virtualItem) => {
            const item = expandedItems[virtualItem.index];

            return (
              <TreeItem
                className={classNames?.item}
                data-index={virtualItem.index}
                disabled={item.data.disabled}
                disabledSelect={disabledSelect}
                disabledToggle={disabledToggle}
                indentSize={indentSize}
                key={item._id}
                level={item.level}
                value={item.value}
                onSelect={onSelect}
                onToggle={onToggle}
              >
                {({ isExpanded, isSelected, isIndeterminate, hasChildren }: TreeItemRenderProps) => {
                  return renderItem
                    ? renderItem({ item, isExpanded, isSelected, isIndeterminate, hasChildren, ...renderProps })
                    : defaultRenderItemContent(item, isExpanded, hasChildren);
                }}
              </TreeItem>
            );
          })}
        </div>
      );
    }

    return virtualItems.map((virtualItem) => {
      const item = expandedItems[virtualItem.index];

      const itemStyle: CSSProperties = {
        position: 'absolute',
        top: 0,
        left: 0,
        width: '100%',
        height: `${virtualItem.size}px`,
        transform: `translateY(${virtualItem.start}px)`
      };

      return (
        <TreeItem
          className={classNames?.item}
          disabled={item.data.disabled}
          disabledSelect={disabledSelect}
          disabledToggle={disabledToggle}
          indentSize={indentSize}
          key={item._id}
          level={item.level}
          style={itemStyle}
          value={item.value}
          onSelect={onSelect}
          onToggle={onToggle}
        >
          {({ isExpanded, isSelected, isIndeterminate, hasChildren }: TreeItemRenderProps) => {
            return renderItem
              ? renderItem({ item, isExpanded, isSelected, isIndeterminate, hasChildren, ...renderProps })
              : defaultRenderItemContent(item, isExpanded, hasChildren);
          }}
        </TreeItem>
      );
    });
  };

  return (
    <TreeRootProvider value={contextValue}>
      <div
        aria-disabled={disabled || undefined}
        aria-multiselectable={multiple || undefined}
        className={cn(virtualContainer(), className, classNames?.virtualContainer)}
        data-disabled={disabled ? '' : undefined}
        ref={rootRef}
        role="tree"
        style={containerStyle}
      >
        {top}

        <ul
          className={cn(virtualContent(), classNames?.root, classNames?.virtualContent)}
          style={contentStyle}
        >
          {renderContent()}
        </ul>

        {bottom}
      </div>
    </TreeRootProvider>
  );
};

